// httpsFetch shim — function-node sandbox lacks global fetch. Uses Node stdlib.
function httpsFetch(urlStr, opts = {}) {
  return new Promise((resolve, reject) => {
    let parsed;
    try { parsed = new urlmod.URL(urlStr); }
    catch (e) { return reject(new Error('bad URL: ' + urlStr)); }
    const isHttps = parsed.protocol === 'https:';
    const lib = isHttps ? https : http;
    const body = opts.body;
    const headers = Object.assign({}, opts.headers || {});
    if (body && !headers['Content-Length']) headers['Content-Length'] = Buffer.byteLength(body);
    const req = lib.request({
      method: opts.method || 'GET',
      hostname: parsed.hostname,
      port: parsed.port || (isHttps ? 443 : 80),
      path: parsed.pathname + (parsed.search || ''),
      headers,
      timeout: opts.timeoutMs || 5000,
      rejectUnauthorized: opts.rejectUnauthorized !== false
    }, (res) => {
      let data = '';
      res.on('data', (c) => { data += c; });
      res.on('end', () => resolve({
        ok: res.statusCode >= 200 && res.statusCode < 300,
        status: res.statusCode,
        headers: res.headers,
        text: () => Promise.resolve(data),
        json: () => { try { return Promise.resolve(JSON.parse(data)); } catch (e) { return Promise.reject(e); } }
      }));
    });
    req.on('error', reject);
    req.on('timeout', () => { req.destroy(new Error('timeout')); });
    if (body) req.write(body);
    req.end();
  });
}

const base = (env.get('KEYCLOAK_ADMIN_URL') || 'https://identity.facis.cloud').replace(/\/$/, '');
const realm = env.get('KEYCLOAK_ADMIN_REALM') || 'facis';
const user = env.get('KEYCLOAK_ADMIN_USER');
const pass = env.get('KEYCLOAK_ADMIN_PASSWORD');
if (!user || !pass) {
  msg.statusCode = 503;
  msg.headers = { 'Content-Type': 'application/json' };
  msg.payload = { detail: 'Keycloak admin credentials not configured. Set KEYCLOAK_ADMIN_USER / KEYCLOAK_ADMIN_PASSWORD on the ORCE pod.' };
  return msg;
}

// URLSearchParams is not exposed in the function-node sandbox; build the body manually.
const formEncode = (obj) => Object.entries(obj)
  .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`)
  .join('&');

async function getToken(force) {
  if (!force) {
    const cached = flow.get('kc_admin_token');
    if (cached && cached.expires_at > Date.now() + 5_000) return cached.token;
  }
  const body = formEncode({ grant_type: 'password', client_id: 'admin-cli', username: user, password: pass });
  const res = await httpsFetch(`${base}/realms/master/protocol/openid-connect/token`, { method: 'POST', headers: { 'Content-Type': 'application/x-www-form-urlencoded' }, body, /* known: pod's Alpine image lacks Let's Encrypt CA chain */ rejectUnauthorized: false });
  if (!res.ok) throw new Error(`token grant failed: ${res.status}`);
  const j = await res.json();
  const ttl = (j.expires_in || 60) * 1000;
  flow.set('kc_admin_token', { token: j.access_token, expires_at: Date.now() + ttl });
  return j.access_token;
}

async function call(path) {
  let token = await getToken(false);
  let res = await httpsFetch(`${base}/admin/realms/${realm}${path}`, { headers: { 'Authorization': `Bearer ${token}` }, rejectUnauthorized: false });
  if (res.status === 401) {
    token = await getToken(true);
    res = await httpsFetch(`${base}/admin/realms/${realm}${path}`, { headers: { 'Authorization': `Bearer ${token}` }, rejectUnauthorized: false });
  }
  if (!res.ok) throw new Error(`KC admin ${path} → ${res.status}`);
  return res.json();
}


// --- Caller authorization (verify JWT via Keycloak userinfo, require 'admin' realm role) ---
const AUTHZ = msg.req && (msg.req.headers && (msg.req.headers.authorization || msg.req.headers.Authorization));
if (!AUTHZ || !AUTHZ.startsWith('Bearer ')) {
  msg.statusCode = 401;
  msg.headers = { 'Content-Type': 'application/json', 'WWW-Authenticate': 'Bearer realm="facis"' };
  msg.payload = { detail: 'Authorization: Bearer <token> required' };
  return msg;
}
const userinfoUrl = `${(env.get('KEYCLOAK_USER_REALM_URL') || 'https://identity.facis.cloud/realms/facis')}/protocol/openid-connect/userinfo`;
try {
  const ui = await httpsFetch(userinfoUrl, { headers: { 'Authorization': AUTHZ }, rejectUnauthorized: false });
  if (!ui.ok) {
    msg.statusCode = 401;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'token rejected by Keycloak userinfo' };
    return msg;
  }
  const claims = await ui.json();
  const roles = (claims && claims.realm_access && claims.realm_access.roles) || [];
  if (!roles.includes('admin')) {
    msg.statusCode = 403;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'admin role required' };
    return msg;
  }
} catch (e) {
  msg.statusCode = 502;
  msg.headers = { 'Content-Type': 'application/json' };
  msg.payload = { detail: 'auth check failed' };
  return msg;
}

try {
  const url = msg.req && msg.req.url || '';
  let payload;
  if (url.startsWith('/api/v1/admin/users')) {
    const users = await call('/users?max=200');
    payload = {
      users: users.map(u => ({
        id: u.id, username: u.username,
        firstName: u.firstName || '', lastName: u.lastName || '',
        email: u.email || '', enabled: u.enabled !== false,
        emailVerified: !!u.emailVerified,
        createdTimestamp: u.createdTimestamp || null,
        federationLink: u.federationLink || null
      })),
      count: users.length
    };
  } else if (url.startsWith('/api/v1/admin/roles')) {
    const roles = await call('/roles');
    // Per-role member count via a fan-out (small N expected; cap to 20).
    const limited = roles.slice(0, 20);
    const counts = await Promise.all(limited.map(async (r) => {
      try { const m = await call(`/roles/${encodeURIComponent(r.name)}/users?max=1000`); return m.length; } catch { return null; }
    }));
    payload = {
      roles: limited.map((r, i) => ({
        name: r.name, description: r.description || '',
        composite: !!r.composite, member_count: counts[i]
      })),
      count: limited.length
    };
  } else if (url.startsWith('/api/v1/admin/access')) {
    const events = await call('/events?max=200&type=LOGIN&type=LOGOUT&type=LOGIN_ERROR');
    payload = {
      events: events.map(e => ({
        id: `${e.type}-${e.time}`,
        type: e.type, timestamp: new Date(e.time).toISOString(),
        user_id: e.userId || null, ip: e.ipAddress || null,
        result: e.error ? 'failed' : 'success',
        details: e.details || null
      })),
      count: events.length
    };
  } else {
    msg.statusCode = 404;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'unknown admin route' };
    return msg;
  }
  msg.statusCode = 200;
  msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
  msg.payload = payload;
} catch (e) {
  msg.statusCode = 502;
  msg.headers = { 'Content-Type': 'application/json' };
  node.warn('Keycloak admin call failed: ' + String(e.message || e));
  msg.payload = { detail: 'Keycloak admin call failed' };
}
return msg;
